   589→// ==================== GANTT CHART TYPES ====================
   590→
   591→export type GanttViewMode = 'day' | 'week' | 'month' | 'quarter';
   592→export type GanttGroupBy = 'status' | 'priority' | 'assignee' | 'none';
   593→export type GanttSortBy = 'start-date' | 'due-date' | 'priority' | 'manual';
   594→
   595→export interface GanttSettings {
   596→  viewMode: GanttViewMode;
   597→  showCriticalPath: boolean;
   598→  showBaseline: boolean;
