     2→ * Task Recurrence Service
     3→ * Handles generation and calculation of recurring task instances
     4→ */
     5→
     6→import { format, addDays, addWeeks, addMonths, addYears, isBefore, isAfter, parseISO, startOfDay } from 'date-fns';
     7→import type { Task } from '../types';
     8→import { logger } from './logger';
     9→
    10→const log = logger.module('TaskRecurrence');
    11→
    12→/**
    13→ * Calculate the next occurrence date based on recurrence rules
    14→ * @param task Task with recurrence rules
    15→ * @param fromDate Starting date (YYYY-MM-DD)
    16→ * @returns Next occurrence date (YYYY-MM-DD) or null if series has ended
    17→ */
    18→export function calculateNextOccurrence(task: Task, fromDate: string): string | null {
    19→  if (!task.recurrence) return null;
    20→
    21→  const { frequency, interval, daysOfWeek, dayOfMonth, endType, endDate } = task.recurrence;
    22→  let nextDate = parseISO(fromDate);
    23→
    24→  // Add interval based on frequency
    25→  switch (frequency) {
    26→    case 'daily':
    27→      nextDate = addDays(nextDate, interval);
    28→      break;
    29→
    30→    case 'weekly':
    31→      // For weekly, find next matching day of week
    32→      if (daysOfWeek && daysOfWeek.length > 0) {
    33→        const currentDay = nextDate.getDay();
    34→        let daysToAdd = interval * 7;
    35→
    36→        // Find next matching day in the cycle
    37→        const sortedDays = [...daysOfWeek].sort((a, b) => a - b);
    38→        const nextMatchingDay = sortedDays.find(day => day > currentDay);
    39→
    40→        if (nextMatchingDay !== undefined) {
    41→          // Next occurrence is this week
    42→          daysToAdd = nextMatchingDay - currentDay;
    43→        } else {
    44→          // Next occurrence is next week (first day in cycle)
    45→          daysToAdd = (interval - 1) * 7 + (7 - currentDay + sortedDays[0]);
    46→        }
    47→
    48→        nextDate = addDays(nextDate, daysToAdd);
    49→      } else {
    50→        nextDate = addWeeks(nextDate, interval);
    51→      }
    52→      break;
    53→
    54→    case 'monthly':
    55→      nextDate = addMonths(nextDate, interval);
    56→
    57→      // If specific day of month is set, adjust
