import React, { useState, useEffect, useCallback } from 'react';
import { Modal } from '../../components/Modal';
import { RecurrencePicker } from '../../components/RecurrencePicker';
import { CustomFieldEditor } from '../../components/CustomFieldEditor';
import { DependencyPicker } from '../../components/DependencyPicker';
import { DependentShiftConfirmation } from '../../components/DependentShiftConfirmation';
import AssigneePicker from '../../components/AssigneePicker';
import FileUpload from '../../components/FileUpload';
import AttachmentList from '../../components/AttachmentList';
import ImagePreviewModal from '../../components/ImagePreviewModal';
import { useKanbanStore } from '../../stores/useKanbanStore';
import { useTimeTrackingStore } from '../../stores/useTimeTrackingStore';
import { useSettingsStore } from '../../stores/useSettingsStore';
import { calculateDependentShifts, shouldAutoShift } from '../../services/taskDependencyShift';
import type { Task, TaskPriority, TaskStatus, EffortEstimate, CustomStatus, DependencyType, TaskDependency, TaskAttachment } from '../../types';
import type { FieldDefinition } from '../../types/customFields';

/**
 * TaskCustomFields - Separate component to properly use hooks
 * Extracted to avoid Rules of Hooks violation (hooks cannot be called inside IIFEs)
 */
const TaskCustomFields: React.FC<{
  task: Task;
  onSave: (taskId: string, updates: Partial<Task>) => void;
}> = ({ task, onSave }) => {
  const { customFieldDefinitions } = useSettingsStore();
  const taskFields = customFieldDefinitions.tasks;

  if (taskFields.length === 0) return null;

  return (
    <div>
      <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
        Custom Fields
      </label>
      <div className="space-y-3">
        {taskFields.map((field: FieldDefinition) => {
          const currentValue = task?.customFields?.[field.id];

          return (
            <div key={field.id}>
              <label className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
                {field.name}
                {field.required && (
                  <span className="text-status-error-text dark:text-status-error-text-dark ml-1">*</span>
                )}
              </label>
              {field.description && (
                <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mb-1">
                  {field.description}
                </p>
              )}
              <CustomFieldEditor
                field={field}
                value={currentValue}
                onChange={(value) => {
                  if (!task) return;
                  const updatedCustomFields = {
                    ...task.customFields,
                    [field.id]: value,
                  };
                  onSave(task.id, { customFields: updatedCustomFields });
                }}
              />
            </div>
          );
        })}
      </div>
    </div>
  );
};

interface CardDetailPanelProps {
  task: Task | null;
  isOpen: boolean;
  onClose: () => void;
  onSave: (taskId: string, updates: Partial<Task>) => void;
  columns: Array<{ id: string; title: string; color: string }>;
  initialTab?: 'subtasks' | 'checklist' | 'comments' | 'activity' | 'timetracking' | 'attachments';
  onCardClick?: (task: Task) => void;
}

/**
 * Card Detail Panel
 * Full-screen modal for viewing and editing task details
 *
 * Features:
 * - Left side: Task metadata (title, description, dates, priority, tags, status)
 * - Right side: Tabs (Checklist, Comments, Activity Log)
 * - Inline editing (auto-save on blur)
 * - Keyboard shortcuts (Esc to close, Cmd+Enter to save)
 * - Tab persistence (remembers last active tab)
 * - Responsive design (mobile, tablet, desktop)
 */
export const CardDetailPanel: React.FC<CardDetailPanelProps> = ({
  task,
  isOpen,
  onClose,
  onSave,
  columns,
  initialTab,
  onCardClick,
}) => {
  // Kanban store actions
  const {
    tasks,
    addChecklistItem,
    updateChecklistItem,
    deleteChecklistItem,
    toggleChecklistItem,
    addComment,
    addSubtask,
    deleteSubtask,
    toggleSubtask,
    addDependency,
    removeDependency,
    getBlocked,
    updateEffort,
    updateCustomStatus,
    startTimer,
    stopTimer: stopKanbanTimer,
    updateTimeEstimate,
    setTaskRecurrence,
    applyDependentShifts,
    addAttachment,
    deleteAttachment,
  } = useKanbanStore();

  // Time tracking store (Phase A: Time Tracking Integration)
  const {
    getEntriesForCard,
    getTotalTimeForCard,
    startTimerForCard,
    stopTimer,
    activeEntry,
  } = useTimeTrackingStore();

  // Tab state with persistence
  const [activeTab, setActiveTab] = useState<'subtasks' | 'checklist' | 'comments' | 'activity' | 'timetracking' | 'attachments'>(() => {
    if (initialTab) return initialTab;
    const saved = localStorage.getItem('kanban-detail-panel-tab');
    return (saved as 'subtasks' | 'checklist' | 'comments' | 'activity' | 'timetracking' | 'attachments') || 'subtasks';
  });

  // Sync activeTab with initialTab when it changes
  useEffect(() => {
    if (initialTab) {
      setActiveTab(initialTab);
    }
  }, [initialTab]);

  // Local state for editing (synced with task prop)
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [startDate, setStartDate] = useState<string | null>(null);
  const [dueDate, setDueDate] = useState<string | null>(null);
  const [priority, setPriority] = useState<TaskPriority>('medium');
  const [tags, setTags] = useState<string[]>([]);
  const [status, setStatus] = useState<TaskStatus>('todo');
  const [newTag, setNewTag] = useState('');
  const [effort, setEffort] = useState<EffortEstimate | undefined>(undefined);
  const [customStatus, setCustomStatus] = useState<CustomStatus | undefined>(undefined);
  const [timeEstimate, setTimeEstimate] = useState<number | undefined>(undefined);
  const [assignees, setAssignees] = useState<string[]>([]);
  const [progress, setProgress] = useState<number>(0); // Phase 1.5: Progress %

  // P1: Recurring tasks state
  const [showRecurrencePicker, setShowRecurrencePicker] = useState(false);

  // Phase 1.2: Auto-shift dependent tasks
  const { autoShiftDependentTasks, setAutoShiftDependentTasks } = useSettingsStore();
  const [pendingShifts, setPendingShifts] = useState<Array<{taskId: string; newStartDate: string | null; newDueDate: string | null; reason: string}> | null>(null);

  // Checklist state
  const [newChecklistItem, setNewChecklistItem] = useState('');

  // Comment state
  const [newCommentText, setNewCommentText] = useState('');

  // Subtask state
  const [showAddSubtaskForm, setShowAddSubtaskForm] = useState(false);
  const [newSubtaskTitle, setNewSubtaskTitle] = useState('');
  const [newSubtaskDescription, setNewSubtaskDescription] = useState('');
  const [newSubtaskPriority, setNewSubtaskPriority] = useState<TaskPriority>('medium');
  const [newSubtaskDueDate, setNewSubtaskDueDate] = useState('');

  // Phase 3.2: Attachment state
  const [previewAttachment, setPreviewAttachment] = useState<TaskAttachment | null>(null);

  // No longer need local state for dependency selection - handled by DependencyPicker

  // Sync local state with task prop when task changes
  useEffect(() => {
    if (task) {
      setTitle(task.title);
      setDescription(task.description);
      setStartDate(task.startDate);
      setDueDate(task.dueDate);
      setPriority(task.priority);
      setTags(task.tags);
      setStatus(task.status);
      setEffort(task.effort);
      setCustomStatus(task.customStatus);
      setTimeEstimate(task.timeTracking?.estimated);
      setAssignees(task.assignees || []);
      setProgress(task.progress || 0); // Phase 1.5
    }
  }, [task]);

  // Tab persistence
  useEffect(() => {
    localStorage.setItem('kanban-detail-panel-tab', activeTab);
  }, [activeTab]);

  // Save and close handler
  const handleSaveAndClose = useCallback(() => {
    if (!task) return;
    onSave(task.id, {
      title,
      description,
      startDate,
      dueDate,
      priority,
      tags,
      status,
      assignees,
    });
    onClose();
  }, [task, onSave, onClose, title, description, startDate, dueDate, priority, tags, status, assignees]);

  // Keyboard shortcut: Cmd+Enter to save and close
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'Enter' && isOpen) {
        e.preventDefault();
        handleSaveAndClose();
      }
    };

    if (isOpen) {
      document.addEventListener('keydown', handleKeyDown);
    }

    return () => {
      document.removeEventListener('keydown', handleKeyDown);
    };
  }, [isOpen, handleSaveAndClose]);

  if (!task) return null;

  const handleFieldBlur = (field: keyof Task, value: unknown) => {
    // Phase 1.2: Check if date change triggers dependent shifts
    if ((field === 'startDate' || field === 'dueDate') && task) {
      const oldStartDate = task.startDate;
      const oldDueDate = task.dueDate;
      const newStartDate = field === 'startDate' ? (value as string | null) : task.startDate;
      const newDueDate = field === 'dueDate' ? (value as string | null) : task.dueDate;

      // Check if auto-shift is enabled and dates actually changed
      if (shouldAutoShift(
        { ...task, startDate: newStartDate, dueDate: newDueDate },
        oldStartDate,
        oldDueDate,
        autoShiftDependentTasks
      )) {
        // Calculate what shifts would be needed
        const shifts = calculateDependentShifts(
          { ...task, startDate: newStartDate, dueDate: newDueDate },
          oldStartDate,
          oldDueDate,
          tasks
        );

        if (shifts.length > 0) {
          // Show confirmation dialog
          setPendingShifts(shifts);
          // Don't save yet - wait for user confirmation
          return;
        }
      }
    }

    // Auto-save on blur (normal case or no shifts needed)
    onSave(task.id, { [field]: value });
  };

  const handleAddTag = () => {
    if (newTag.trim() && !tags.includes(newTag.trim())) {
      const updatedTags = [...tags, newTag.trim()];
      setTags(updatedTags);
      onSave(task.id, { tags: updatedTags });
      setNewTag('');
    }
  };

  const handleRemoveTag = (tagToRemove: string) => {
    const updatedTags = tags.filter(tag => tag !== tagToRemove);
    setTags(updatedTags);
    onSave(task.id, { tags: updatedTags });
  };

  // Dependency handlers
  const handleAddDependency = (dependency: TaskDependency) => {
    if (!task) return;
    addDependency(task.id, dependency);
  };

  const handleRemoveDependency = (dependencyId: string) => {
    if (!task) return;
    removeDependency(task.id, dependencyId);
  };

  // Get dependency label for display
  const getDependencyLabel = (type: DependencyType): string => {
    const labels = {
      'finish-to-start': 'FS',
      'start-to-start': 'SS',
      'finish-to-finish': 'FF',
      'start-to-finish': 'SF',
    };
    return labels[type];
  };

  const getDependencyIcon = (type: DependencyType): string => {
    const icons = {
      'finish-to-start': '⏭️',
      'start-to-start': '🤝',
      'finish-to-finish': '🏁',
      'start-to-finish': '🔄',
    };
    return icons[type];
  };

  // Phase 1.2: Shift confirmation handlers
  const handleConfirmShifts = () => {
    if (!pendingShifts || !task) return;

    // Apply the date change to the current task first
    const dateField = startDate !== task.startDate ? 'startDate' : 'dueDate';
    const dateValue = startDate !== task.startDate ? startDate : dueDate;
    onSave(task.id, { [dateField]: dateValue });

    // Then apply all dependent shifts
    applyDependentShifts(pendingShifts);

    // Close dialog
    setPendingShifts(null);
  };

  const handleCancelShifts = () => {
    if (!task) return;

    // Revert local state to original values
    setStartDate(task.startDate);
    setDueDate(task.dueDate);

    // Close dialog
    setPendingShifts(null);
  };

  const handleDontAskAgain = () => {
    // Disable auto-shift
    setAutoShiftDependentTasks(false);

    // Close dialog without applying shifts
    handleCancelShifts();
  };

  const availableTasks = tasks.filter(t => t.id !== task?.id);

  return (
    <>
    <Modal isOpen={isOpen} onClose={onClose} title={task.title} maxWidth="2xl">
      <div className="flex flex-col md:flex-row gap-3 pr-1">
        {/* Left Side: Task Metadata (60%) */}
        <div className="w-full md:w-3/5 space-y-2">
          {/* Title */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-1">
              Title
            </label>
            <input
              type="text"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              onBlur={() => handleFieldBlur('title', title)}
              className="w-full text-base font-semibold bg-transparent border-none outline-none text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue rounded px-1 py-0.5"
              autoFocus
            />
          </div>

          {/* Description */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-1">
              Description
            </label>
            <textarea
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              onBlur={() => handleFieldBlur('description', description)}
              placeholder="Add a description..."
              className="w-full min-h-[48px] p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-xs text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary focus:ring-2 focus:ring-accent-blue outline-none resize-y"
              rows={2}
            />
          </div>

          {/* Dates */}
          <div className={`grid ${task?.isMilestone ? 'grid-cols-1' : 'grid-cols-2'} gap-4`}>
            {/* Phase 1.6: Hide start date for milestones (single-point events) */}
            {!task?.isMilestone && (
              <div>
                <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
                  Start Date
                </label>
                <input
                  type="date"
                value={startDate || ''}
                onChange={(e) => {
                  setStartDate(e.target.value || null);
                  handleFieldBlur('startDate', e.target.value || null);
                }}
                className="w-full p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
              />
              </div>
            )}
            <div>
              <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
                {task?.isMilestone ? 'Milestone Date' : 'Due Date'}
              </label>
              <input
                type="date"
                value={dueDate || ''}
                onChange={(e) => {
                  setDueDate(e.target.value || null);
                  handleFieldBlur('dueDate', e.target.value || null);
                }}
                className="w-full p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
              />
            </div>
          </div>

          {/* Priority */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Priority
            </label>
            <select
              value={priority}
              onChange={(e) => {
                const newPriority = e.target.value as TaskPriority;
                setPriority(newPriority);
                handleFieldBlur('priority', newPriority);
              }}
              className="w-full p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
            >
              <option value="low">Low</option>
              <option value="medium">Medium</option>
              <option value="high">High</option>
            </select>
          </div>

          {/* Milestone Checkbox - Phase 1.6 */}
          <div className="flex items-center gap-2 p-3 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-lg">
            <input
              type="checkbox"
              id="is-milestone"
              checked={task?.isMilestone || false}
              onChange={(e) => {
                const isMilestone = e.target.checked;
                handleFieldBlur('isMilestone', isMilestone);

                // If marking as milestone, clear start date (milestones are single-point events)
                if (isMilestone && task?.startDate) {
                  handleFieldBlur('startDate', null);
                  setStartDate(null);
                }
              }}
              className="w-4 h-4 rounded border-border-light dark:border-border-dark bg-surface-light dark:bg-surface-dark text-accent-blue focus:ring-2 focus:ring-accent-blue cursor-pointer"
            />
            <label
              htmlFor="is-milestone"
              className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary cursor-pointer select-none"
            >
              📍 Mark as Milestone (key deadline/deliverable)
            </label>
          </div>

          {/* Assignees - Phase 3.1 */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Assignees
            </label>
            <AssigneePicker
              selectedIds={assignees}
              onChange={(newAssignees) => {
                setAssignees(newAssignees);
                handleFieldBlur('assignees', newAssignees);
              }}
            />
          </div>

          {/* Effort (Story Points) - Phase B */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Effort (Story Points)
            </label>
            <select
              value={effort || ''}
              onChange={(e) => {
                const newEffort = e.target.value ? (parseInt(e.target.value) as EffortEstimate) : undefined;
                setEffort(newEffort);
                if (task) {
                  updateEffort(task.id, newEffort);
                }
              }}
              className="w-full p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
            >
              <option value="">None</option>
              <option value="1">1 - Trivial</option>
              <option value="2">2 - Minor</option>
              <option value="3">3 - Medium</option>
              <option value="5">5 - Major</option>
              <option value="8">8 - Large</option>
              <option value="13">13 - Epic</option>
            </select>
          </div>

          {/* Custom Status - Phase B */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Custom Status
            </label>
            <select
              value={customStatus || ''}
              onChange={(e) => {
                const newStatus = e.target.value ? (e.target.value as CustomStatus) : undefined;
                setCustomStatus(newStatus);
                if (task) {
                  updateCustomStatus(task.id, newStatus);
                }
              }}
              className="w-full p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
            >
              <option value="">None</option>
              <option value="in-review">In Review</option>
              <option value="testing">Testing</option>
              <option value="deployed">Deployed</option>
              <option value="blocked">Blocked</option>
            </select>
          </div>

          {/* Time Estimate - Phase B */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Time Estimate (hours)
            </label>
            <input
              type="number"
              min="0"
              step="0.5"
              value={timeEstimate || ''}
              onChange={(e) => {
                const hours = e.target.value ? parseFloat(e.target.value) : undefined;
                setTimeEstimate(hours);
                if (task && hours !== undefined) {
                  updateTimeEstimate(task.id, hours);
                }
              }}
              placeholder="e.g., 4.5"
              className="w-full p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
            />
            {task && (
              <div className="mt-2 space-y-2">
                <div className="flex items-center justify-between text-xs text-text-light-secondary dark:text-text-dark-secondary">
                  <span>Actual: {((task.timeTracking?.actual || 0) / 3600).toFixed(1)}h</span>
                  {task.timeTracking?.activeTimerStart && (
                    <span className="animate-pulse text-accent-blue font-semibold">⏱️ Running</span>
                  )}
                </div>
                {task.timeTracking?.activeTimerStart ? (
                  <button
                    onClick={() => stopKanbanTimer(task.id)}
                    className="w-full px-3 py-1.5 bg-status-error text-white text-xs font-medium rounded hover:bg-status-error/90 transition-colors"
                  >
                    ⏹️ Stop Timer
                  </button>
                ) : (
                  <button
                    onClick={() => startTimer(task.id)}
                    className="w-full px-3 py-1.5 bg-accent-blue text-white text-xs font-medium rounded hover:bg-accent-blue-hover transition-colors"
                  >
                    ▶️ Start Timer
                  </button>
                )}
              </div>
            )}
          </div>

          {/* Progress - Phase 1.5 */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Progress (%)
            </label>

            {/* Slider */}
            <input
              type="range"
              min="0"
              max="100"
              step="5"
              value={progress}
              onChange={(e) => {
                const newProgress = parseInt(e.target.value);
                setProgress(newProgress);
                handleFieldBlur('progress', newProgress);
              }}
              className="w-full h-2 bg-neutral-200 dark:bg-neutral-700 rounded-lg appearance-none cursor-pointer accent-accent-blue"
            />

            {/* Numeric input + quick-set buttons */}
            <div className="flex items-center gap-2 mt-2">
              <input
                type="number"
                min="0"
                max="100"
                value={progress}
                onChange={(e) => {
                  const val = Math.min(100, Math.max(0, parseInt(e.target.value) || 0));
                  setProgress(val);
                  handleFieldBlur('progress', val);
                }}
                className="w-20 p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
              />
              <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">%</span>

              {/* Quick-set buttons */}
              <div className="flex gap-1 ml-auto">
                {[0, 25, 50, 75, 100].map((val) => (
                  <button
                    key={val}
                    onClick={() => {
                      setProgress(val);
                      handleFieldBlur('progress', val);
                    }}
                    className={`px-2 py-1 text-xs rounded transition-colors ${
                      progress === val
                        ? 'bg-accent-blue text-white'
                        : 'bg-neutral-100 dark:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary hover:bg-neutral-200 dark:hover:bg-neutral-700'
                    }`}
                  >
                    {val}%
                  </button>
                ))}
              </div>
            </div>
          </div>

          {/* Tags */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Tags
            </label>
            <div className="flex flex-wrap gap-2 mb-2">
              {tags.map((tag) => (
                <span
                  key={tag}
                  className="inline-flex items-center gap-1 px-3 py-1 bg-accent-blue text-white text-xs font-medium rounded-full"
                >
                  {tag}
                  <button
                    onClick={() => handleRemoveTag(tag)}
                    className="hover:text-accent-blue-hover"
                    aria-label={`Remove tag ${tag}`}
                  >
                    ✕
                  </button>
                </span>
              ))}
            </div>
            <div className="flex gap-2">
              <input
                type="text"
                value={newTag}
                onChange={(e) => setNewTag(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter') {
                    e.preventDefault();
                    handleAddTag();
                  }
                }}
                placeholder="Add a tag..."
                className="flex-1 p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary focus:ring-2 focus:ring-accent-blue outline-none"
              />
              <button
                onClick={handleAddTag}
                className="px-4 py-2 bg-accent-blue hover:bg-accent-blue-hover text-white text-sm font-medium rounded-lg transition-colors"
              >
                Add
              </button>
            </div>
          </div>

          {/* P1: Recurring Tasks */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Recurrence
            </label>

            {/* Show current recurrence or button to add */}
            {!showRecurrencePicker && (
              <div>
                {task?.recurrence ? (
                  <div className="space-y-2">
                    {/* Recurrence Summary */}
                    <div className="p-3 bg-accent-blue/10 dark:bg-accent-blue/20 rounded-lg">
                      <div className="flex items-start justify-between gap-2">
                        <div className="flex-1">
                          <p className="text-xs text-text-light-primary dark:text-text-dark-primary font-medium mb-1">
                            {(() => {
                              const { frequency, interval, daysOfWeek, dayOfMonth } = task.recurrence;
                              let summary = 'Repeats ';

                              // Frequency and interval
                              if (interval === 1) {
                                summary += frequency;
                              } else {
                                summary += `every ${interval} ${frequency === 'daily' ? 'days' : frequency === 'weekly' ? 'weeks' : frequency === 'monthly' ? 'months' : 'years'}`;
                              }

                              // Days of week (for weekly)
                              if (frequency === 'weekly' && daysOfWeek && daysOfWeek.length > 0) {
                                const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
                                const selectedDays = daysOfWeek.map((d) => dayNames[d]).join(', ');
                                summary += ` on ${selectedDays}`;
                              }

                              // Day of month (for monthly)
                              if (frequency === 'monthly' && dayOfMonth) {
                                summary += ` on day ${dayOfMonth}`;
                              }

                              return summary;
                            })()}
                          </p>
                          {task.recurrence.endType !== 'never' && (
                            <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
                              {task.recurrence.endType === 'after' && task.recurrence.endCount &&
                                `Ends after ${task.recurrence.endCount} occurrences`
                              }
                              {task.recurrence.endType === 'until' && task.recurrence.endDate &&
                                `Ends on ${task.recurrence.endDate}`
                              }
                            </p>
                          )}
                          {task.isRecurringParent && task.nextOccurrence && (
                            <p className="text-xs text-accent-blue font-medium mt-1">
                              Next: {task.nextOccurrence}
                            </p>
                          )}
                          {task.recurrenceId && (
                            <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
                              Instance of recurring task
                            </p>
                          )}
                        </div>
                        <button
                          onClick={() => setShowRecurrencePicker(true)}
                          className="text-xs text-accent-blue hover:text-accent-blue-hover"
                        >
                          Edit
                        </button>
                      </div>
                    </div>
                  </div>
                ) : (
                  <button
                    onClick={() => setShowRecurrencePicker(true)}
                    className="w-full p-2 bg-surface-light-elevated dark:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary text-sm rounded-lg hover:bg-surface-light dark:hover:bg-neutral-700 transition-colors"
                  >
                    + Add Recurrence
                  </button>
                )}
              </div>
            )}

            {/* Recurrence Picker */}
            {showRecurrencePicker && (
              <div className="mt-2">
                <RecurrencePicker
                  value={task?.recurrence}
                  onChange={(recurrence) => {
                    if (task) {
                      setTaskRecurrence(task.id, recurrence);
                      setShowRecurrencePicker(false);
                    }
                  }}
                  onClose={() => setShowRecurrencePicker(false)}
                />
              </div>
            )}
          </div>

          {/* Dependencies (Professional PM) */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-3">
              Dependencies
            </label>

            {/* Current Dependencies */}
            {task?.dependencies && task.dependencies.length > 0 ? (
              <div className="space-y-2 mb-4">
                {task.dependencies.map((dep) => {
                  const blockerTask = tasks.find(t => t.id === dep.taskId);
                  if (!blockerTask) return null;

                  // P1: Check if blocker is overdue
                  const isOverdue = blockerTask.status !== 'done' &&
                    blockerTask.dueDate &&
                    new Date(blockerTask.dueDate).setHours(0,0,0,0) < new Date().setHours(0,0,0,0);

                  const daysOverdue = isOverdue && blockerTask.dueDate
                    ? Math.floor((new Date().getTime() - new Date(blockerTask.dueDate).getTime()) / (1000 * 60 * 60 * 24))
                    : 0;

                  return (
                    <div
                      key={dep.taskId}
                      className="flex items-center gap-2 p-2 bg-status-warning-bg dark:bg-status-warning-bg-dark rounded-lg border border-status-warning dark:border-status-warning hover:border-status-warning-hover dark:hover:border-status-warning-hover transition-colors group cursor-pointer"
                      onClick={() => {
                        // Navigate to blocker task
                        if (onCardClick) {
                          onCardClick(blockerTask);
                        }
                      }}
                    >
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2">
                          <span className="text-sm">{getDependencyIcon(dep.type)}</span>
                          <div className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary truncate">
                            {blockerTask.title}
                          </div>
                          {/* P1: Overdue blocker warning */}
                          {isOverdue && (
                            <span className="shrink-0 inline-flex items-center px-1.5 py-0.5 rounded text-[10px] font-medium bg-status-error-bg dark:bg-status-error-bg-dark text-status-error-text dark:text-status-error-text-dark border border-status-error-border dark:border-status-error-border-dark">
                              ⚠️ {daysOverdue}d overdue
                            </span>
                          )}
                        </div>
                        <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary ml-6">
                          {getDependencyLabel(dep.type)} • {blockerTask.status}
                          {dep.lag !== 0 && (
                            <span className="ml-2">
                              {dep.lag > 0 ? `+${dep.lag}` : dep.lag} day{Math.abs(dep.lag) !== 1 ? 's' : ''}
                              {dep.lag > 0 ? ' delay' : ' lead'}
                            </span>
                          )}
                        </div>
                      </div>
                      <button
                        onClick={(e) => {
                          e.stopPropagation(); // Prevent navigation when removing
                          handleRemoveDependency(dep.taskId);
                        }}
                        className="opacity-0 group-hover:opacity-100 text-text-light-secondary hover:text-status-error transition-opacity"
                        title="Remove dependency"
                      >
                        ✕
                      </button>
                    </div>
                  );
                })}
              </div>
            ) : (
              <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary py-1 mb-3">
                🔓 No dependencies
              </div>
            )}

            {/* Blocked By (Tasks that depend on this one) */}
            {task && getBlocked(task.id).length > 0 && (
              <div className="mb-4">
                <div className="text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
                  🔒 Blocks These Tasks
                </div>
                <div className="space-y-1">
                  {getBlocked(task.id).map((blocked) => (
                    <div
                      key={blocked.id}
                      className="flex items-center gap-2 p-2 bg-accent-blue/10 dark:bg-accent-blue/20 rounded-lg border border-accent-blue/30 dark:border-accent-blue/30 cursor-pointer hover:border-accent-blue transition-colors"
                      onClick={() => {
                        if (onCardClick) {
                          onCardClick(blocked);
                        }
                      }}
                    >
                      <div className="text-sm text-text-light-primary dark:text-text-dark-primary truncate">
                        {blocked.title}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Add New Dependency */}
            <div className="border-t border-border-light dark:border-border-dark pt-3 mt-3">
              <div className="text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-3">
                Add Dependency
              </div>
              {task && (
                <DependencyPicker
                  currentTask={task}
                  availableTasks={availableTasks}
                  existingDependencies={task.dependencies || []}
                  onAdd={handleAddDependency}
                />
              )}
            </div>
          </div>

          {/* Status */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Status (Column)
            </label>
            <select
              value={status}
              onChange={(e) => {
                const newStatus = e.target.value as TaskStatus;
                setStatus(newStatus);
                handleFieldBlur('status', newStatus);
              }}
              className="w-full p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
            >
              {columns.map((column) => (
                <option key={column.id} value={column.id}>
                  {column.title}
                </option>
              ))}
            </select>
          </div>

          {/* Custom Fields (P2 #3) */}
          <TaskCustomFields task={task} onSave={onSave} />
        </div>

        {/* Right Side: Tabs (40%) */}
        <div className="w-full md:w-2/5">
          {/* Tab Navigation */}
          <div className="border-b border-border-light dark:border-border-dark mb-2">
            <div className="flex gap-2">
              <button
                onClick={() => setActiveTab('subtasks')}
                className={`pb-1 px-1 text-xs font-medium transition-colors ${
                  activeTab === 'subtasks'
                    ? 'text-accent-blue border-b-2 border-accent-blue'
                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
                }`}
              >
                Subtasks {task.subtasks && task.subtasks.length > 0 && `(${task.subtasks.length})`}
              </button>
              <button
                onClick={() => setActiveTab('checklist')}
                className={`pb-1 px-1 text-xs font-medium transition-colors ${
                  activeTab === 'checklist'
                    ? 'text-accent-blue border-b-2 border-accent-blue'
                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
                }`}
              >
                Checklist
              </button>
              <button
                onClick={() => setActiveTab('comments')}
                className={`pb-1 px-1 text-xs font-medium transition-colors ${
                  activeTab === 'comments'
                    ? 'text-accent-blue border-b-2 border-accent-blue'
                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
                }`}
              >
                Comments
              </button>
              <button
                onClick={() => setActiveTab('activity')}
                className={`pb-1 px-1 text-xs font-medium transition-colors ${
                  activeTab === 'activity'
                    ? 'text-accent-blue border-b-2 border-accent-blue'
                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
                }`}
              >
                Activity
              </button>
              <button
                onClick={() => setActiveTab('timetracking')}
                className={`pb-1 px-1 text-xs font-medium transition-colors ${
                  activeTab === 'timetracking'
                    ? 'text-accent-blue border-b-2 border-accent-blue'
                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
                }`}
              >
                Time
              </button>
              <button
                onClick={() => setActiveTab('attachments')}
                className={`pb-1 px-1 text-xs font-medium transition-colors ${
                  activeTab === 'attachments'
                    ? 'text-accent-blue border-b-2 border-accent-blue'
                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
                }`}
              >
                Attachments {task.attachments && task.attachments.length > 0 && `(${task.attachments.length})`}
              </button>
            </div>
          </div>

          {/* Tab Content */}
          <div className="py-2">
            {/* Subtasks Tab */}
            {activeTab === 'subtasks' && (
              <div className="space-y-4">
                {/* Progress Bar */}
                {task.subtasks && task.subtasks.length > 0 && (() => {
                  const completedCount = task.subtasks.filter(st => st.completed).length;
                  const totalCount = task.subtasks.length;

                  return (
                    <div>
                      <div className="flex justify-between text-sm mb-2">
                        <span className="font-medium text-text-light-primary dark:text-text-dark-primary">Progress</span>
                        <span className="text-text-light-secondary dark:text-text-dark-secondary">
                          {completedCount} of {totalCount}
                        </span>
                      </div>
                      <div className="w-full bg-neutral-200 dark:bg-neutral-700 rounded-full h-2">
                        <div
                          className="bg-accent-blue h-2 rounded-full transition-all"
                          style={{ width: `${(completedCount / totalCount) * 100}%` }}
                        />
                      </div>
                    </div>
                  );
                })()}

                {/* Subtask List */}
                {task.subtasks && task.subtasks.length > 0 ? (
                  <div className="space-y-2">
                    {[...task.subtasks].sort((a, b) => a.order - b.order).map((subtask) => (
                      <div
                        key={subtask.id}
                        className="flex items-start gap-3 p-3 bg-neutral-50 dark:bg-neutral-800 rounded-lg hover:bg-neutral-100 dark:hover:bg-neutral-700 transition-colors"
                      >
                        {/* Checkbox */}
                        <input
                          type="checkbox"
                          checked={subtask.completed}
                          onChange={() => toggleSubtask(task.id, subtask.id)}
                          className="mt-1 cursor-pointer"
                        />

                        {/* Content */}
                        <div className="flex-1 min-w-0">
                          <div className={`text-sm font-medium ${
                            subtask.completed
                              ? 'text-text-light-secondary dark:text-text-dark-secondary line-through'
                              : 'text-text-light-primary dark:text-text-dark-primary'
                          }`}>
                            {subtask.title}
                          </div>
                          {subtask.description && (
                            <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
                              {subtask.description}
                            </div>
                          )}
                          {/* Metadata */}
                          <div className="flex gap-2 mt-2 flex-wrap">
                            {subtask.priority && (
                              <span className={`text-xs px-2 py-0.5 rounded ${
                                subtask.priority === 'high'
                                  ? 'bg-status-error text-white'
                                  : subtask.priority === 'medium'
                                  ? 'bg-status-warning text-white'
                                  : 'bg-status-info text-white'
                              }`}>
                                {subtask.priority.charAt(0).toUpperCase() + subtask.priority.slice(1)}
                              </span>
                            )}
                            {subtask.dueDate && (
                              <span className="text-xs px-2 py-0.5 rounded bg-neutral-200 dark:bg-neutral-700 text-text-light-secondary dark:text-text-dark-secondary">
                                📅 {new Date(subtask.dueDate).toLocaleDateString()}
                              </span>
                            )}
                          </div>
                        </div>

                        {/* Delete Button */}
                        <button
                          onClick={() => deleteSubtask(task.id, subtask.id)}
                          className="text-text-light-secondary dark:text-text-dark-secondary hover:text-status-error transition-colors"
                          title="Delete subtask"
                        >
                          ✕
                        </button>
                      </div>
                    ))}
                  </div>
                ) : (
                  <div className="text-center py-2">
                    <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
                      📝 No subtasks yet
                    </p>
                  </div>
                )}

                {/* Add Subtask Form */}
                {showAddSubtaskForm ? (
                  <div className="p-4 bg-neutral-50 dark:bg-neutral-800 rounded-lg space-y-3">
                    <input
                      type="text"
                      value={newSubtaskTitle}
                      onChange={(e) => setNewSubtaskTitle(e.target.value)}
                      placeholder="Subtask title"
                      className="w-full px-3 py-2 text-sm border border-border-light dark:border-border-dark rounded-lg bg-white dark:bg-neutral-900 text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary focus:outline-none focus:ring-2 focus:ring-accent-blue"
                      autoFocus
                    />
                    <textarea
                      value={newSubtaskDescription}
                      onChange={(e) => setNewSubtaskDescription(e.target.value)}
                      placeholder="Description (optional)"
                      rows={2}
                      className="w-full px-3 py-2 text-sm border border-border-light dark:border-border-dark rounded-lg bg-white dark:bg-neutral-900 text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary focus:outline-none focus:ring-2 focus:ring-accent-blue resize-none"
                    />
                    <div className="grid grid-cols-2 gap-3">
                      <div>
                        <label className="block text-xs text-text-light-secondary dark:text-text-dark-secondary mb-1">Priority</label>
                        <select
                          value={newSubtaskPriority}
                          onChange={(e) => setNewSubtaskPriority(e.target.value as TaskPriority)}
                          className="w-full px-3 py-2 text-sm border border-border-light dark:border-border-dark rounded-lg bg-white dark:bg-neutral-900 text-text-light-primary dark:text-text-dark-primary"
                        >
                          <option value="low">Low</option>
                          <option value="medium">Medium</option>
                          <option value="high">High</option>
                        </select>
                      </div>
                      <div>
                        <label className="block text-xs text-text-light-secondary dark:text-text-dark-secondary mb-1">Due Date</label>
                        <input
                          type="date"
                          value={newSubtaskDueDate}
                          onChange={(e) => setNewSubtaskDueDate(e.target.value)}
                          className="w-full px-3 py-2 text-sm border border-border-light dark:border-border-dark rounded-lg bg-white dark:bg-neutral-900 text-text-light-primary dark:text-text-dark-primary"
                        />
                      </div>
                    </div>
                    <div className="flex gap-2">
                      <button
                        onClick={() => {
                          if (!newSubtaskTitle.trim()) return;

                          addSubtask(task.id, {
                            title: newSubtaskTitle.trim(),
                            description: newSubtaskDescription.trim() || undefined,
                            priority: newSubtaskPriority,
                            dueDate: newSubtaskDueDate || undefined,
                            completed: false,
                          });

                          // Reset form
                          setNewSubtaskTitle('');
                          setNewSubtaskDescription('');
                          setNewSubtaskPriority('medium');
                          setNewSubtaskDueDate('');
                          setShowAddSubtaskForm(false);
                        }}
                        disabled={!newSubtaskTitle.trim()}
                        className="flex-1 px-4 py-2 text-sm bg-accent-blue text-white rounded-lg hover:bg-accent-blue-hover transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                      >
                        Add Subtask
                      </button>
                      <button
                        onClick={() => {
                          setShowAddSubtaskForm(false);
                          setNewSubtaskTitle('');
                          setNewSubtaskDescription('');
                          setNewSubtaskPriority('medium');
                          setNewSubtaskDueDate('');
                        }}
                        className="px-4 py-2 text-sm bg-neutral-200 dark:bg-neutral-700 text-text-light-primary dark:text-text-dark-primary rounded-lg hover:opacity-80 transition-opacity"
                      >
                        Cancel
                      </button>
                    </div>
                  </div>
                ) : (
                  <button
                    onClick={() => setShowAddSubtaskForm(true)}
                    className="w-full px-4 py-2 text-sm bg-neutral-100 dark:bg-neutral-800 text-text-light-primary dark:text-text-dark-primary rounded-lg hover:bg-neutral-200 dark:hover:bg-neutral-700 transition-colors"
                  >
                    + Add Subtask
                  </button>
                )}
              </div>
            )}

            {activeTab === 'checklist' && (
              <div className="space-y-4">
                {/* Progress Bar */}
                {task.checklist && task.checklist.length > 0 && (
                  <div>
                    <div className="flex justify-between text-sm mb-2">
                      <span className="font-medium text-text-light-primary dark:text-text-dark-primary">Progress</span>
                      <span className="text-text-light-secondary dark:text-text-dark-secondary">
                        {task.checklist.filter(item => item.completed).length} of {task.checklist.length}
                      </span>
                    </div>
                    <div className="w-full bg-neutral-200 dark:bg-neutral-700 rounded-full h-2">
                      <div
                        className="bg-accent-blue h-2 rounded-full transition-all"
                        style={{ width: `${(task.checklist.filter(item => item.completed).length / task.checklist.length) * 100}%` }}
                      />
                    </div>
                  </div>
                )}

                {/* Checklist Items */}
                <div className="space-y-2">
                  {task.checklist && task.checklist.length > 0 ? (
                    task.checklist
                      .sort((a, b) => a.order - b.order)
                      .map((item) => (
                        <div key={item.id} className="flex items-start gap-2 group">
                          <input
                            type="checkbox"
                            checked={item.completed}
                            onChange={() => toggleChecklistItem(task.id, item.id)}
                            className="mt-1 cursor-pointer"
                          />
                          <input
                            type="text"
                            value={item.text}
                            onChange={(e) => updateChecklistItem(task.id, item.id, { text: e.target.value })}
                            className={`flex-1 px-2 py-1 text-sm bg-transparent border-none outline-none ${
                              item.completed ? 'line-through text-text-light-secondary dark:text-text-dark-secondary' : 'text-text-light-primary dark:text-text-dark-primary'
                            } focus:ring-1 focus:ring-accent-blue rounded`}
                          />
                          <button
                            onClick={() => deleteChecklistItem(task.id, item.id)}
                            className="opacity-0 group-hover:opacity-100 text-status-error hover:text-status-error-hover transition-opacity px-2"
                            aria-label="Delete item"
                          >
                            ✕
                          </button>
                        </div>
                      ))
                  ) : (
                    <div className="text-center py-2 text-text-light-secondary dark:text-text-dark-secondary text-xs">
                      ✓ No checklist items
                    </div>
                  )}
                </div>

                {/* Add New Item */}
                <div className="flex gap-2">
                  <input
                    type="text"
                    value={newChecklistItem}
                    onChange={(e) => setNewChecklistItem(e.target.value)}
                    onKeyDown={(e) => {
                      if (e.key === 'Enter' && newChecklistItem.trim()) {
                        e.preventDefault();
                        addChecklistItem(task.id, newChecklistItem.trim());
                        setNewChecklistItem('');
                      }
                    }}
                    placeholder="Add item..."
                    className="flex-1 px-3 py-2 text-sm border border-border-light dark:border-border-dark rounded-lg bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
                  />
                  <button
                    onClick={() => {
                      if (newChecklistItem.trim()) {
                        addChecklistItem(task.id, newChecklistItem.trim());
                        setNewChecklistItem('');
                      }
                    }}
                    className="px-4 py-2 bg-accent-blue hover:bg-accent-blue-hover text-white text-sm font-medium rounded-lg transition-colors"
                  >
                    Add
                  </button>
                </div>
              </div>
            )}

            {activeTab === 'comments' && (
              <div className="space-y-4">
                {/* Comments List */}
                <div className="space-y-3 max-h-[400px] overflow-y-auto">
                  {task.comments && task.comments.length > 0 ? (
                    task.comments
                      .sort((a, b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime())
                      .map((comment) => (
                        <div key={comment.id} className="bg-surface-light-elevated dark:bg-surface-dark p-3 rounded-lg">
                          <div className="flex justify-between items-start mb-2">
                            <span className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary">{comment.author}</span>
                            <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
                              {new Date(comment.createdAt).toLocaleString()}
                            </span>
                          </div>
                          <p className="text-sm text-text-light-primary dark:text-text-dark-primary whitespace-pre-wrap">{comment.text}</p>
                        </div>
                      ))
                  ) : (
                    <div className="text-center py-2 text-text-light-secondary dark:text-text-dark-secondary text-xs">
                      💬 No comments yet
                    </div>
                  )}
                </div>

                {/* Add Comment Form */}
                <div className="space-y-2">
                  <textarea
                    value={newCommentText}
                    onChange={(e) => setNewCommentText(e.target.value)}
                    placeholder="Add a comment..."
                    className="w-full p-3 text-sm border border-border-light dark:border-border-dark rounded-lg bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none resize-y"
                    rows={3}
                  />
                  <button
                    onClick={() => {
                      if (newCommentText.trim()) {
                        addComment(task.id, newCommentText.trim());
                        setNewCommentText('');
                      }
                    }}
                    className="px-4 py-2 bg-accent-blue hover:bg-accent-blue-hover text-white text-sm font-medium rounded-lg transition-colors"
                  >
                    Post Comment
                  </button>
                </div>
              </div>
            )}

            {activeTab === 'activity' && (
              <div className="space-y-3 max-h-[500px] overflow-y-auto">
                {task.activityLog && task.activityLog.length > 0 ? (
                  task.activityLog
                    .sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime())
                    .map((entry) => (
                      <div key={entry.id} className="flex gap-3 items-start">
                        <div className="w-2 h-2 mt-2 rounded-full bg-accent-blue flex-shrink-0" />
                        <div className="flex-1">
                          <p className="text-sm text-text-light-primary dark:text-text-dark-primary">
                            {entry.action === 'created' && 'Created task'}
                            {entry.action === 'updated' && entry.field && `Updated ${entry.field}`}
                            {entry.action === 'moved' && 'Moved to different column'}
                            {entry.action === 'commented' && 'Added comment'}
                            {entry.action === 'checklist_updated' && 'Updated checklist'}
                            {entry.oldValue && entry.newValue && (
                              <span className="text-text-light-secondary dark:text-text-dark-secondary">
                                {' '}from "{entry.oldValue}" to "{entry.newValue}"
                              </span>
                            )}
                          </p>
                          <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
                            {new Date(entry.timestamp).toLocaleString()}
                          </span>
                        </div>
                      </div>
                    ))
                ) : (
                  <div className="text-center py-2 text-text-light-secondary dark:text-text-dark-secondary text-xs">
                    📋 No activity yet
                  </div>
                )}
              </div>
            )}

            {/* Time Tracking Tab (Phase A: Time Tracking Integration) */}
            {activeTab === 'timetracking' && task && (() => {
              const entries = getEntriesForCard(task.id);
              const totalSeconds = getTotalTimeForCard(task.id);
              const isTimerActive = activeEntry?.taskId === task.id;

              const formatDuration = (seconds: number): string => {
                const hours = Math.floor(seconds / 3600);
                const minutes = Math.floor((seconds % 3600) / 60);
                const secs = seconds % 60;
                return `${hours}h ${minutes}m ${secs}s`;
              };

              const formatTime = (seconds: number): string => {
                const hours = seconds / 3600;
                return hours < 0.1 ? '<0.1h' : `${hours.toFixed(1)}h`;
              };

              return (
                <div className="space-y-4">
                  {/* Timer Controls */}
                  <div className="bg-surface-light-elevated dark:bg-surface-dark rounded-lg p-4">
                    <div className="flex items-center justify-between mb-3">
                      <div>
                        <h3 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary">
                          Total Time: {formatTime(totalSeconds)}
                        </h3>
                        <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
                          {formatDuration(totalSeconds)}
                        </p>
                      </div>
                      {isTimerActive ? (
                        <button
                          onClick={() => stopTimer()}
                          className="px-4 py-2 bg-status-error text-white text-sm font-medium rounded-lg hover:bg-status-error/90 transition-colors flex items-center gap-2"
                        >
                          <span className="animate-pulse">⏱️</span>
                          Stop Timer
                        </button>
                      ) : (
                        <button
                          onClick={() => startTimerForCard(task.id, task.title)}
                          className="px-4 py-2 bg-accent-blue text-white text-sm font-medium rounded-lg hover:bg-accent-blue-hover transition-colors flex items-center gap-2"
                        >
                          ▶️ Start Timer
                        </button>
                      )}
                    </div>

                    {/* Estimated Hours Comparison */}
                    {task.estimatedHours && (
                      <div className="pt-3 border-t border-border-light dark:border-border-dark">
                        <div className="flex items-center justify-between text-xs">
                          <span className="text-text-light-secondary dark:text-text-dark-secondary">
                            Estimated: {task.estimatedHours}h
                          </span>
                          <span className={`font-medium ${
                            totalSeconds / 3600 > task.estimatedHours
                              ? 'text-status-error'
                              : 'text-status-success'
                          }`}>
                            {totalSeconds / 3600 > task.estimatedHours
                              ? `Over by ${((totalSeconds / 3600) - task.estimatedHours).toFixed(1)}h`
                              : `${(task.estimatedHours - (totalSeconds / 3600)).toFixed(1)}h remaining`
                            }
                          </span>
                        </div>
                        {/* Progress Bar */}
                        <div className="mt-2 w-full bg-neutral-200 dark:bg-neutral-700 rounded-full h-2">
                          <div
                            className={`h-2 rounded-full transition-all ${
                              totalSeconds / 3600 > task.estimatedHours
                                ? 'bg-status-error'
                                : 'bg-accent-blue'
                            }`}
                            style={{
                              width: `${Math.min(100, (totalSeconds / 3600 / task.estimatedHours) * 100)}%`,
                            }}
                          />
                        </div>
                      </div>
                    )}
                  </div>

                  {/* Time Entries List */}
                  <div>
                    <h4 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary mb-2">
                      Time Entries ({entries.length})
                    </h4>
                    {entries.length > 0 ? (
                      <div className="space-y-2 max-h-[400px] overflow-y-auto">
                        {entries.map((entry, index) => (
                          <div
                            key={entry.id || index}
                            className="bg-surface-light-elevated dark:bg-surface-dark rounded-lg p-3 border border-border-light dark:border-border-dark"
                          >
                            <div className="flex items-start justify-between gap-2">
                              <div className="flex-1">
                                <p className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary">
                                  {entry.description}
                                </p>
                                <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
                                  {new Date(entry.startTime).toLocaleString()}
                                  {entry.endTime && ` - ${new Date(entry.endTime).toLocaleTimeString()}`}
                                </p>
                              </div>
                              <div className="text-right">
                                <p className={`text-sm font-semibold ${
                                  !entry.endTime
                                    ? 'text-accent-blue animate-pulse'
                                    : 'text-text-light-primary dark:text-text-dark-primary'
                                }`}>
                                  {formatTime(entry.duration)}
                                </p>
                                {!entry.endTime && (
                                  <p className="text-xs text-accent-blue">Running...</p>
                                )}
                              </div>
                            </div>
                          </div>
                        ))}
                      </div>
                    ) : (
                      <div className="text-center py-2 text-text-light-secondary dark:text-text-dark-secondary text-xs">
                        ⏱️ No time entries yet
                      </div>
                    )}
                  </div>
                </div>
              );
            })()}

            {/* Attachments Tab (Phase 3.2) */}
            {activeTab === 'attachments' && task && (
              <div className="space-y-4">
                {/* File Upload */}
                <div>
                  <h4 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary mb-3">
                    Upload Files
                  </h4>
                  <FileUpload
                    onUpload={(file) => {
                      addAttachment(task.id, {
                        filename: file.filename,
                        fileType: file.fileType,
                        fileSize: file.fileSize,
                        dataUrl: file.dataUrl,
                      });
                    }}
                  />
                </div>

                {/* Attachment List */}
                <div>
                  <h4 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary mb-3">
                    Attachments ({task.attachments?.length || 0})
                  </h4>
                  <AttachmentList
                    attachments={task.attachments || []}
                    onDelete={(attachmentId) => deleteAttachment(task.id, attachmentId)}
                    onPreview={(attachment) => setPreviewAttachment(attachment)}
                  />
                </div>

                {/* Phase 3.4: Card Cover Mode Selector (only show when image attachments exist) */}
                {task.attachments?.some(a => a.fileType.startsWith('image/')) && (
                  <div>
                    <h4 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary mb-3">
                      Card Cover Display
                    </h4>
                    <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mb-2">
                      Choose how the first image appears on the card
                    </p>
                    <div className="flex gap-2">
                      <button
                        onClick={() => onSave(task.id, { coverMode: 'fit' })}
                        className={`flex-1 px-3 py-2 rounded-lg text-sm font-medium transition-colors ${
                          task.coverMode === 'fit' || !task.coverMode
                            ? 'bg-accent-blue text-white'
                            : 'bg-surface-light-elevated dark:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary hover:bg-neutral-100 dark:hover:bg-neutral-700'
                        }`}
                      >
                        Fit (show full image)
                      </button>
                      <button
                        onClick={() => onSave(task.id, { coverMode: 'fill' })}
                        className={`flex-1 px-3 py-2 rounded-lg text-sm font-medium transition-colors ${
                          task.coverMode === 'fill'
                            ? 'bg-accent-blue text-white'
                            : 'bg-surface-light-elevated dark:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary hover:bg-neutral-100 dark:hover:bg-neutral-700'
                        }`}
                      >
                        Fill (crop to fit)
                      </button>
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Footer: Keyboard Hints */}
      <div className="mt-2 pt-2 border-t border-border-light dark:border-border-dark">
        <p className="text-[10px] text-text-light-secondary dark:text-text-dark-secondary text-center">
          Press <kbd className="px-1 py-0.5 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded text-[10px]">Esc</kbd> to close
          or <kbd className="px-1 py-0.5 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded text-[10px]">Cmd+Enter</kbd> to save
        </p>
      </div>
    </Modal>

    {/* Phase 1.2: Dependent shift confirmation dialog */}
    {pendingShifts && pendingShifts.length > 0 && (
      <DependentShiftConfirmation
        shifts={pendingShifts}
        tasks={tasks}
        onConfirm={handleConfirmShifts}
        onCancel={handleCancelShifts}
        onDontAskAgain={handleDontAskAgain}
      />
    )}

    {/* Phase 3.2: Image preview modal */}
    {previewAttachment && (
      <ImagePreviewModal
        attachment={previewAttachment}
        onClose={() => setPreviewAttachment(null)}
      />
    )}
    </>
  );
};

