                          </span>
                          <span className={`font-medium ${
                            totalSeconds / 3600 > task.estimatedHours
                              ? 'text-status-error'
                              : 'text-status-success'
                          }`}>
                            {totalSeconds / 3600 > task.estimatedHours
                              ? `Over by ${((totalSeconds / 3600) - task.estimatedHours).toFixed(1)}h`
                              : `${(task.estimatedHours - (totalSeconds / 3600)).toFixed(1)}h remaining`
                            }
                          </span>
                        </div>
                        {/* Progress Bar */}
                        <div className="mt-2 w-full bg-neutral-200 dark:bg-neutral-700 rounded-full h-2">
                          <div
                            className={`h-2 rounded-full transition-all ${
                              totalSeconds / 3600 > task.estimatedHours
                                ? 'bg-status-error'
                                : 'bg-accent-blue'
                            }`}
                            style={{
                              width: `${Math.min(100, (totalSeconds / 3600 / task.estimatedHours) * 100)}%`,
                            }}
                          />
                        </div>
                      </div>
                    )}
                  </div>

                  {/* Time Entries List */}
                  <div>
                    <h4 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary mb-2">
                      Time Entries ({entries.length})
                    </h4>
                    {entries.length > 0 ? (
                      <div className="space-y-2 max-h-[400px] overflow-y-auto">
                        {entries.map((entry, index) => (
                          <div
                            key={entry.id || index}
                            className="bg-surface-light-elevated dark:bg-surface-dark rounded-lg p-3 border border-border-light dark:border-border-dark"
                          >
                            <div className="flex items-start justify-between gap-2">
                              <div className="flex-1">
                                <p className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary">
                                  {entry.description}
                                </p>
                                <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
                                  {new Date(entry.startTime).toLocaleString()}
                                  {entry.endTime && ` - ${new Date(entry.endTime).toLocaleTimeString()}`}
                                </p>
                              </div>
                              <div className="text-right">
                                <p className={`text-sm font-semibold ${
                                  !entry.endTime
                                    ? 'text-accent-blue animate-pulse'
                                    : 'text-text-light-primary dark:text-text-dark-primary'
                                }`}>
                                  {formatTime(entry.duration)}
                                </p>
                                {!entry.endTime && (
                                  <p className="text-xs text-accent-blue">Running...</p>
                                )}
                              </div>
                            </div>
                          </div>
                        ))}
                      </div>
                    ) : (
                      <div className="text-center py-2 text-text-light-secondary dark:text-text-dark-secondary text-xs">
                        ⏱️ No time entries yet
                      </div>
                    )}
                  </div>
                </div>
              );
            })()}

            {/* Attachments Tab (Phase 3.2) */}
            {activeTab === 'attachments' && task && (
              <div className="space-y-4">
                {/* File Upload */}
                <div>
                  <h4 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary mb-3">
                    Upload Files
                  </h4>
                  <FileUpload
                    onUpload={(file) => {
                      addAttachment(task.id, {
                        filename: file.filename,
                        fileType: file.fileType,
                        fileSize: file.fileSize,
                        dataUrl: file.dataUrl,
                      });
                    }}
                  />
                </div>

                {/* Attachment List */}
                <div>
                  <h4 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary mb-3">
                    Attachments ({task.attachments?.length || 0})
                  </h4>
                  <AttachmentList
                    attachments={task.attachments || []}
                    onDelete={(attachmentId) => deleteAttachment(task.id, attachmentId)}
                    onPreview={(attachment) => setPreviewAttachment(attachment)}
                  />
                </div>

                {/* Phase 3.4: Card Cover Mode Selector (only show when image attachments exist) */}
                {task.attachments?.some(a => a.fileType.startsWith('image/')) && (
                  <div>
                    <h4 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary mb-3">
                      Card Cover Display
                    </h4>
                    <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mb-2">
                      Choose how the first image appears on the card
                    </p>
                    <div className="flex gap-2">
                      <button
                        onClick={() => onSave(task.id, { coverMode: 'fit' })}
                        className={`flex-1 px-3 py-2 rounded-lg text-sm font-medium transition-colors ${
                          task.coverMode === 'fit' || !task.coverMode
                            ? 'bg-accent-blue text-white'
                            : 'bg-surface-light-elevated dark:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary hover:bg-neutral-100 dark:hover:bg-neutral-700'
                        }`}
                      >
                        Fit (show full image)
                      </button>
                      <button
                        onClick={() => onSave(task.id, { coverMode: 'fill' })}
                        className={`flex-1 px-3 py-2 rounded-lg text-sm font-medium transition-colors ${
                          task.coverMode === 'fill'
                            ? 'bg-accent-blue text-white'
                            : 'bg-surface-light-elevated dark:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary hover:bg-neutral-100 dark:hover:bg-neutral-700'
                        }`}
                      >
                        Fill (crop to fit)
                      </button>
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Footer: Keyboard Hints */}
      <div className="mt-2 pt-2 border-t border-border-light dark:border-border-dark">
        <p className="text-[10px] text-text-light-secondary dark:text-text-dark-secondary text-center">
          Press <kbd className="px-1 py-0.5 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded text-[10px]">Esc</kbd> to close
          or <kbd className="px-1 py-0.5 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded text-[10px]">Cmd+Enter</kbd> to save
        </p>
      </div>
    </Modal>

    {/* Phase 1.2: Dependent shift confirmation dialog */}
    {pendingShifts && pendingShifts.length > 0 && (
      <DependentShiftConfirmation
        shifts={pendingShifts}
        tasks={tasks}
        onConfirm={handleConfirmShifts}
        onCancel={handleCancelShifts}
        onDontAskAgain={handleDontAskAgain}
      />
    )}

    {/* Phase 3.2: Image preview modal */}
    {previewAttachment && (
      <ImagePreviewModal
        attachment={previewAttachment}
        onClose={() => setPreviewAttachment(null)}
      />
    )}
    </>
  );
};

